examples.bad:
class HomeViewModel {
  var timer: Timer?
  // ❌ No deinit — timer keeps firing, ViewModel never deallocated
}

examples.good:
class HomeViewModel {
  var timer: Timer?
  deinit {
    timer?.invalidate()
    NotificationCenter.default.removeObserver(self)
  }
}

private var cancellables = Set<AnyCancellable>()

viewModel.$balance
  .sink { [weak self] in self?.updateUI($0) }
  .store(in: &cancellables)
